<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list ref="tgList" :listType="listType" :IsShowAction="true" :showCheckBox="true" ModuleName="PROJECT"
            SubModuleCode="Project_Detail" IdentityColumn="project_id" :HeaderText="$t('Manage Project')"
            :ListData="ProjectData" :HeaderData="Headers" :widgets="widgets" :HeaderButtons="listheaderbuttons"
            :TotalRecords="TotalRecords" :SearchFields="leftSearchFields" :RenderRowActionMethod="renderActions"
            :ListDataCallBackFunction="FetchData" :SortExp="SortExp" :ViewList="ViewList" v-on:ApplyView="OnApplyView"
            :SortBy="SortBy" :LegendArray="LegendArray" :NorecordfoundText="$t('NoRecordfound')"
            v-on:LeftsearchButtonClick="leftCommonSearch" :isNewDesign="isNewDesign" v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick"
            v-on:SortdataButtonClick="sortdata" :key="Key" :routeInfo="$router">
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'status_id' && (UserType != 'NU' && UserType != 'CL')">
                    <listing-status :isfor="'PROJECTLISTING'" ref="updatestatus" v-bind:dataid="data.row.project_id"
                        data-controller="PROJECT" v-bind:statuslist="StatusListForListing" v-bind:item="data"
                        data-action="index" v-bind:dataselected="data.row.project_status"
                        :disabled="data.row.project_status === 'Active'" v-bind:callbackfunction="FetchData"
                        v-bind:isselectedvaluestring="true">
                    </listing-status>

                </template>
                <template v-if="data.column.COLUMN_NAME == 'status_id' && (UserType == 'NU' || UserType == 'CL')">
                    <a class="inactive-disabled">
                        <span v-bind:style="{ backgroundColor: data.row.status_bg_color }"
                            class="text-center text-white d-block">
                            {{ data.row.project_status }}
                        </span>
                    </a>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'planned_start_date'">
                    <span :title="data.row.planned_start_date != null ? $d(data.row.planned_start_date) : '--'">
                        {{ data.row.planned_start_date != null ? $d(data.row.planned_start_date) : '--' }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'planned_end_date'">
                    <span :title="data.row.planned_end_date != null ? $d(data.row.planned_end_date) : '--'">
                        {{ data.row.planned_end_date != null ? $d(data.row.planned_end_date) : '--' }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'priority_id'">
                    <span v-bind:style="{ backgroundColor: data.row.color_code }" v-if="data.row.priority_id != ''"
                        class="text-center text-white d-block">
                        {{ data.row.priority_id }}
                    </span>
                    <span v-else v-bind:style="{ backgroundColor: data.row.color_code }" class="text-center d-block">
                        {{ 'N/A' }}
                    </span>
                </template>

                <template v-if="data.column.COLUMN_NAME == 'current_progress'">
                    <span class="d-flex">
                        <div class="Task clockposition">
                            <div>
                                <progress id="progress-bar-1" :value="data.row.current_progress" max="100"></progress>
                                <div class="vue-simple-progress-text" id="progress-text"
                                    style="color: rgb(34, 34, 34); font-size: 12px; text-align: center; padding-top: 3px;">
                                    {{ data.row.current_progress }} % {{ $t('Completed') }}</div>
                            </div>
                        </div>
                        <a v-if="(data.row.IS_INCLUDE_IN_TASK > 0 || UserType != 'CL') && data.row.PROJECTTASKPROGRESS != 'TIMER_BASED'"
                            class="text-success align-top mt-0 d-inline-block text-right" data-toggle-tooltip="tooltip"
                            data-original-title="Manage Progress" @click="EditTaskProgress(data.row, this)">
                            <i class="fa fa-clock-o text-secondary float-left"></i>
                        </a>
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'project_name'">
                    <em class="fa fa-thumb-tack font-13 text-dark pr-2 float-left pt-1"
                        v-on:click="MarkAsUnPin(data.row.project_id)" v-if="data.row.pin_id > 0"></em>
                    <span :title="data.row.project_name" style="color: dodgerblue;cursor: pointer; white-space: nowrap;  word-wrap: break-word;  overflow: hidden;  display: block;  text-overflow: ellipsis;
                         " @click="ProjectDetail(data.row)"> {{ data.row.project_name }}</span>
                </template>             
                <template v-if="data.column.COLUMN_NAME == 'estimated_hours'">
                    {{ $n(data.row.estimated_hours, 'decimal2') }}
                </template>
                <template v-if="data.column.COLUMN_NAME == 'currency_conversion_rate'">
                    <span>{{ $n(data.row.currency_conversion_rate, 'decimal2') + ' ' + data.row.iso_code }}/</span>
                    <span class="bg-warning text-dark">{{ $n(data.row.orignal_convertion_amount, 'decimal2') == 'NaN'
                        ? '0.00' : $n(data.row.orignal_convertion_amount, 'decimal2') }}</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'estimated_cost'">
                    <span :title="$n(data.row.estimated_cost, 'currency', $getLocaleByCurrency(data.row.iso_code))">
                        {{ $n(data.row.estimated_cost, "currency", $getLocaleByCurrency(data.row.iso_code)) }}
                    </span>
                </template>

                <template v-if="data.column.COLUMN_NAME == 'template_id'">
                    <span :title="data.row.TEMPLATE_NAME" style="white-space: nowrap;  word-wrap: break-word;  overflow: hidden;  display: block;  text-overflow: ellipsis;">
                        {{ data.row.TEMPLATE_NAME }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'industry_type_id'">
                    <span :title="data.row.INDUSTRY_NAME" style="white-space: nowrap;  word-wrap: break-word;  overflow: hidden;  display: block;  text-overflow: ellipsis;">
                        {{ data.row.INDUSTRY_NAME }}
                    </span>
                </template>
            </template>
            <template v-slot:customcard="{ data }">
                <div class="modern-card" :class="{
                    'virtual-bg': data.row.is_virtual_user_enabled == true,
                    'normal-bg': data.row.is_virtual_user_enabled == false,
                    'sample-card': data.row.is_sample_data == 1
                }" :style="{
                    border: data.row.is_virtual_user_enabled ? '2px solid #22c55e' : '2px solid #3b82f6',
                    borderTop: data.row.is_virtual_user_enabled ? '5px solid #16a34a' : '5px solid #1d4ed8'
                }">

                    <!-- HEADER -->
                    <div class="modern-header">

                        <div class="left-section">
                            <div class="custom-control custom-checkbox custom-control-inline">
                                <input type="checkbox" class="chkItems custom-control-input modern-checkbox"
                                    v-on:change="ForCheckBoxClear($event)" :value="data.row.project_id"
                                    :id="'chk' + data.row.project_id" style="display: none;">
                                <label class="custom-control-label" type="checkbox"
                                    :for="'chk' + data.row.project_id"></label>
                                <a href="javascript:;" @click="ProjectDetail(data.row)"
                                    class="text-truncate expense-title ml-1 pt-1" data-toggle-tooltip="tooltip"
                                    style="cursor: default;">{{
                                        TruncateStr(data.row.project_name, 34) }}</a>
                            </div>              
                        </div>

                        <div class="right-section">

                            <!-- PIN -->
                            <i v-if="data.row.pin_id > 0" class="fa fa-thumb-tack cursor-pointer text-dark"
                                @click="MarkAsUnPin(data.row.project_id)">
                            </i>

                            <!-- 3 DOT -->
                            <div class="menu-wrapper">
                                <i class="fa fa-ellipsis-v menu-icon" @click.stop="toggleMenu(data.row.project_id)">
                                </i>


                                <div v-if="activeMenu === data.row.project_id" class="dropdown-menu-modern">

                                    <div v-if="UserType != 'NU' && UserType != 'CL'">

                                        <div v-if="data.row.user_type_id == 2 || UserType == 'CA'">
                                            <i class="fa fa-times close close-action mt-0" @click.stop="closeMenu">
                                            </i>
                                            <a @click="btnTeamAdd(data.row)">
                                                <i class="fa fa-users text-info"></i> {{ $t('AddTeam') }}
                                            </a>

                                            <a @click="navigateToGanttChart(data.row.project_id, data.row)">
                                                <i class="fa fa-area-chart"></i> {{ $t('GanttChart') }}
                                            </a>

                                            <a @click="RoadMap(data.row.project_id)">
                                                <i class="fa fa-line-chart"></i> {{ $t('RoadMap') }}
                                            </a>

                                            <a @click="Quotation(data.row)">
                                                <i class="fa fa-file"></i> {{ $t('Quotation') }}
                                            </a>
                                            <a v-if="UserType != 'CL'" @click="AssignedTasks(data.row.project_id)">
                                                <i class="fa fa-clock-o"></i> {{ $t('AssignedTasks') }}
                                            </a>

                                        </div>
                                    </div>



                                </div>
                            </div>

                        </div>
                    </div>

                    <!-- STATUS -->
                    <div class="modern-row">
                        <i class="fa fa-exclamation-triangle"></i>
                        <span>{{ $t('Status') }} -</span>

                        <div v-if="(data.row.project_status != '' && UserType != 'NU' && UserType != 'CL')">
                            <listing-status :isfor="'PROJECTLISTING'" :dataid="data.row.project_id"
                                data-controller="PROJECT" :statuslist="StatusListForListing" :item="data"
                                data-action="index" :dataselected="data.row.project_status"
                                :callbackfunction="FetchData" :isselectedvaluestring="true">
                            </listing-status>
                        </div>

                        <div v-if="((UserType == 'NU' || UserType == 'PM') && data.row.user_type_id == 3)">
                            <span class="status-badge"
                                :style="{ backgroundColor: data.row.status_bg_color, color: data.row.status_color }">
                                {{ data.row.project_status }}
                            </span>
                        </div>
                    </div>

                    <!-- LOCATION -->
                    <div class="modern-row">
                        <i class="fa fa-map-marker"></i>
                        <span>{{ $t('Location') }} - {{ data.row.location_name }}</span>
                    </div>

                    <!-- COST -->
                    <div class="modern-row" v-if="UserType != 'CL'">
                        <i class="fa fa-money"></i>
                        <span>
                            {{ $t('ProjectCost') }} -
                            {{ $n(data.row.estimated_cost, 'decimal2') }}
                            {{ data.row.iso_code }}
                        </span>

                        <span class="amount-chip">
                            {{
                                $n(data.row.orignal_convertion_amount, 'decimal2') == 'NaN'
                                    ? '0.00'
                                    : $n(data.row.orignal_convertion_amount, 'decimal2')
                            }}
                        </span>
                    </div>

                    <!-- DATE -->
                    <div class="modern-row" v-if="data.row.planned_start_date && data.row.planned_end_date">
                        <em class="fa fa-calendar"></em>
                        <span>
                            {{ $d(data.row.planned_start_date) }} -
                            {{ $d(data.row.planned_end_date) }}
                        </span>
                    </div>

                    <!-- PROGRESS -->
                    <div class="progress-section">
                        <div class="progress-label">
                            <span>{{ $t('Completed') }}</span> -
                            <span>{{ data.row.current_progress }}%</span>
                        </div>

                        <div class="progress-bar">
                            <div class="progress-fill" :style="{ width: data.row.current_progress + '%' }">
                            </div>
                        </div>
                    </div>

                    <!-- MORE -->
                    <div class="more-toggle text-right">
                        <a @click="toggleMore(data.row.project_id)" href="javascript:;">
                            {{ expandedCard === data.row.project_id ? $t('Less') : $t('More') }} <em class="mt-1"
                                :class="expandedCard === data.row.project_id ? 'fa fa-angle-double-up' : 'fa fa-angle-double-down'"></em>
                        </a>
                    </div>

                    <!-- EXPAND -->
                    <div v-if="expandedCard === data.row.project_id" class="expand-section">

                        <div class="action-buttons">

                            <a v-if="UserType != 'NU' && UserType != 'CL'" @click="EditProjectt(data.row.project_id)"
                                class="action-btn primary">
                                <i class="fa fa-pencil"></i> {{ $t('Edit') }}
                            </a>

                            <a @click="QuickView(data.row.project_id)" class="action-btn success">
                                <i class="fa fa-eye"></i> {{ $t('QuickView') }}
                            </a>

                            <a v-if="UserType != 'NU' && UserType != 'CL'"
                                @click="OpenCloneProjectModel(data.row.project_id)" class="action-btn warning">
                                <i class="fa fa-clone"></i> {{ $t('CloneProject') }}
                            </a>

                            <a v-if="UserType != 'NU' && UserType != 'CL'"
                                @click="openConfigurationModel(data.row.project_id)" class="action-btn dark">
                                <i class="fa fa-cog"></i> {{ $t('Configurations') }}
                            </a>

                        </div>

                    </div>

                </div>
            </template>






        </tg-list>
        <UpdateStatusProject v-if="IsUpdateStatusProject" :ProjectIds="IsUpdateStatusProjectId"></UpdateStatusProject>
        <AssignTag v-if="ShowAssignTag" :ProjectIds="IsUpdateStatusProjectId" @CallBackFunction="CloseAssignTag">
        </AssignTag>
        <ImportProjects v-if="IsImportProjects"></ImportProjects>
        <viewlayout v-if="ShowManageView" v-show="ShowManageView" submodulecode="PROJECT_DETAIL" modulename="PROJECT"
            v-on:close="ShowManageView = false" v-bind:callbackfunction="FetchData" :usertype="UserType">
            <h5 slot="header">{{ $t('Search') }}</h5>
        </viewlayout>
        <AddProject v-show="IsAddProject" :ProjectId="ProjectId" :Type="IsType" @callbackfunction="CloseProjectModal">
        </AddProject>
        <AddProjectNew v-if="IsAddProjectt" :ProjectId="ProjectId" :Type="IsType" @callbackfunction="CloseProjectModall"
            :key="key"></AddProjectNew>
        <AddTeam v-if="IsAddTeamShow" :ProjectId="ProjectId" :projectCurrency="projectCurrency" :Type="IsType"
            @close="HideIsAddTeamShow" @callbackfunction="FetchData"></AddTeam>
        <MakeProjectDefault v-if="IsMakeProjectDefault" :ProjectId="ProjectId" :ProjectName="ProjectName">
        </MakeProjectDefault>
        <ProjectQuickView v-if="IsProjectQuickView" :ProjectId="ProjectId" @ProjectQuickView="ProjectQuickView">
        </ProjectQuickView>
        <CloneProject v-if="IsCloneProject" :ProjectId="ProjectId"></CloneProject>
        <Configurations v-if="IsConfiguration" :ProjectId="ProjectId"></Configurations>
    </section>
</template>
<script>
import Schema from './ProjectSchema';
import DataService from '../../../services/DataService';
import UpdateStatusProject from '../../../components/Modal/UpdateStatusProject.vue'
import AssignTag from '../../../components/Modal/Manageassigntag.vue'
import ImportProjects from '../../../components/Modal/ImportProjects.vue'
import viewlayout from "../../../components/Common/view-layout.vue";
import AddProject from '../../../components/Modal/AddProject.vue'
import AddTeam from '../../../components/Modal/AddTeam.vue'
import MakeProjectDefault from '../../../components/Modal/MakeProjectDefault.vue'
import ProjectQuickView from '../../../components/Modal/ProjectQuickView.vue'
import CloneProject from '../../../components/Modal/CloneProject.vue'
import Configurations from '../../../components/Modal/ConfigurationModal.vue'
import AddProjectNew from '../../../components/Modal/AddProjectNew.vue'

export default {
    components: { UpdateStatusProject, AssignTag, ImportProjects, viewlayout, AddProject, AddTeam, MakeProjectDefault, ProjectQuickView, CloneProject, Configurations, AddProjectNew },
    data() {
        return {
            Key: 0,
            activeMenu: null,
            expandedCard: null,
            IsType: 'Project',
            isNewDesign: false,
            isLoading: false,
            IsCloneProject: false,
            ShowMoreFalse: false,
            ProjectId: 0,
            searchCondition: '',
            TotalRecords: 0,
            PageNumber: 1,
            PageSize: 10,
            SortBy: '',
            SortExp: '',
            Headers: [],
            ProjectData: [],
            ViewListId: '',
            viewId: 0,
            ViewList: [],
            listType: ['List', 'Card'],
            Type: '',
            listheaderbuttons: Schema.buttons,
            leftSearchFields: Schema.leftsearchSchema,
            listActions: Schema.listActions,
            widgets: [
                {
                    icon: "fa fa-folder",
                    value: "",
                    name: this.$t('Projects'),
                    class: "one_wid",
                    onClick: this.widgetClick
                },
                {
                    icon: "fa fa-folder-open",
                    value: "",
                    name: this.$t('In_Progress'),
                    class: "two_wid",
                    onClick: this.widgetClick
                },
                {
                    icon: "fa fa-dollar",
                    value: "",
                    name: this.$t('TotalRevenue'),
                    class: "three_wid",
                    onClick: this.widgetClick
                },
                {
                    icon: "fa fa-calendar-check-o",
                    value: "",
                    name: this.$t('Completed'),
                    class: "four_wid",
                    onClick: this.widgetClick
                },
                {
                    icon: "fa fa-list-ul",
                    value: "",
                    name: this.$t('Closed'),
                    class: "five_wid",
                    onClick: this.widgetClick
                }
            ],
            LegendArray: [
                {
                    class: 'legend-Progress colorboxsquare',
                    text: (this.$t('VirtualUserEnabled_project', ['Project']))
                },
                {
                    class: 'legend-pending colorboxsquare',
                    text: (this.$t('OriginalCost'))
                }
            ],
            completedStatusId: null,
            ongoingStatusId: null,
            inprogressStatusId: null,
            closedStatusId: null,
            fav: '',
            StatusListForListing: [],
            userId: null,
            companyId: null,
            IsUpdateStatusProject: false,
            IsUpdateStatusProjectId: null,
            ShowAssignTag: false,
            IsImportProjects: false,
            ShowManageView: false,
            UserType: null,
            IsAddProject: false,
            IsAddProjectt: false,
            ProjectEditId: 0,
            IsAddTeamShow: false,
            ProjectId: 0,
            IsMakeProjectDefault: false,
            IsProjectQuickView: false,
            IsConfiguration: false,
            ProjectName: null,
            CurrencyCode: 'PKR',
            key: 0,
            projectCurrency: ''
        }
    },
    mounted() {
        document.addEventListener("click", this.closeAll)
    },

    beforeUnmount() {
        document.removeEventListener("click", this.closeAll)
    },
    created: async function () {
        var ths = this;
        ths.userId = ths.GetUserInfo.ID;
        ths.companyId = ths.GetUserInfo.CompanyId;
        ths.UserType = ths.GetUserInfo.UserType;
        ths.CurrencyCode = ths.GetUserInfo.Currency.replace(/[()]/g, '');
        if (ths.UserType == 'NU' || ths.UserType == 'CL') {
            var array = ths.listheaderbuttons.filter(obj => obj.title?.toLowerCase() === "pin");
            ths.listheaderbuttons = [...array];
        }
        else {
            ths.listheaderbuttons = ths.listheaderbuttons;
        }
        await ths.GetStatusList();
        await ths.GetDdlRecords_ViewList();
        await ths.Widget();
        await Schema.bindleftCommonSearchdropdown(ths, "PROJECT", "CHANNEL");
        await Schema.bindleftCommonSearchdropdown(ths, "PROJECT", "Status");
        await ths.FetchData();
    },

    methods: {
        toggleMenu(id) {
            this.activeMenu = this.activeMenu === id ? null : id
        },

        toggleMore(id) {
            this.expandedCard = this.expandedCard === id ? null : id
        },

        closeAll() {
            this.activeMenu = null
        },


        closeMenu() {
            this.activeMenu = null;
        },
        statusClass(status) {
            if (status === "Active") return "status-active";
            if (status === "Inprogress") return "status-progress";
            if (status === "Cancelled") return "status-cancelled";
            return "";
        },
        CloseAssignTag() {
            this.ShowAssignTag = false;
            this.FetchData();
        },

        ManageView: function () {
            var vm = this;
            vm.ShowManageView = true;
            setTimeout(function () {
                $("#modalManageView").modal("show");
            }, 1000);
        },
        GetDdlRecords_ViewList: async function () {
            var vm = this;
            vm.ViewList = [];
            var url = `moduleName=PROJECT&subModuleCode=PROJECT_DETAIL&viewId=0&pageSize=100&pageNum=1&sortBy=&sortExp=`;
            await DataService.GetViewList(url).then(function (response) {
                if (response.data && typeof (response.data.DATA) != 'undefined') {
                    vm.ViewList = response.data.DATA;
                }
                var chkVACTIVE = 0;
                vm.ViewListId = "0";
                if (vm.ViewList == null || vm.ViewList == "") {

                }
                else {
                    vm.ViewList.forEach(function (item) {

                        if (item.IS_SLECTED_USER_ID > 0) {
                            chkVACTIVE = chkVACTIVE + 1;
                            vm.ViewListId = item.VIEW_ID;
                        }
                    });
                }
                var indx = 0;
                if (chkVACTIVE > 0) {
                    vm.ViewList.splice(indx, 0, { "SUB_MODULE_NAME": "", "SUB_MODULE_CODE": "", "VIEW_NAME": "Default View", "VIEW_ID": 0, "IS_APPLICABLE_TO_ALL": 1, "MODULE_NAME": "", "CREATED_AT": "", "IS_SLECTED_USER_ID": 0, "CAN_EDIT": 0, "ROWNUMBER": 0, "VIEW_TYPE": "", "USER_LIST": "" });
                }
                else {
                    if (vm.ViewList == null || vm.ViewList == "") {

                        vm.ViewList.push({ "SUB_MODULE_NAME": "", "SUB_MODULE_CODE": "", "VIEW_NAME": "Default View", "VIEW_ID": 0, "IS_APPLICABLE_TO_ALL": 1, "MODULE_NAME": "", "CREATED_AT": "", "IS_SLECTED_USER_ID": 1, "CAN_EDIT": 0, "ROWNUMBER": 0, "VIEW_TYPE": "", "USER_LIST": "" });
                    }
                    else {
                        vm.ViewList.splice(indx, 0, { "SUB_MODULE_NAME": "", "SUB_MODULE_CODE": "", "VIEW_NAME": "Default View", "VIEW_ID": 0, "IS_APPLICABLE_TO_ALL": 1, "MODULE_NAME": "", "CREATED_AT": "", "IS_SLECTED_USER_ID": 1, "CAN_EDIT": 0, "ROWNUMBER": 0, "VIEW_TYPE": "", "USER_LIST": "" });

                    }
                }
                setTimeout(() => {
                    if (vm.ViewListId > 0) {
                        vm.$refs.tgList.$refs.tgListHeaderButtons.ViewListId = vm.ViewListId;
                    } else {
                        vm.$refs.tgList.$refs.tgListHeaderButtons.ViewListId = "0";
                    }
                }, 1000);

            });
        },
        DefaultView: function () {
            var vm = this;
            var obj = {
                ModuleName: 'PROJECT',
                SubmoduleCode: 'PROJECT_DETAIL'
            };
            var objectPostString = JSON.stringify(obj);
            DataService.ClearView(objectPostString).then(function (response) {
                if (response.data != null) {
                    if (response.data.code == "1" || response.data.Code == "1") {
                        vm.ShowAlert(vm.$t("ApplySuccess", [vm.$t("DefaultView")]), 'success', true, vm.$t('Alert'));
                        vm.FetchData();
                    }
                    else {
                        vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), 'failure', true, vm.$t('Alert'));
                    }
                }
                else {
                    vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), 'failure', true, vm.$t('Alert'));
                }
            });
        },
        OnApplyView(viewId) {
            var vm = this;
            if (viewId == '0') {
                vm.DefaultView()
            }
            else {
                var obj = {
                    ViewId: viewId,
                    ModuleName: 'PROJECT',
                    SubmoduleCode: 'PROJECT_DETAIL'
                };
                var objectPostString = JSON.stringify(obj);
                DataService.ApplyView(objectPostString).then(function (response) {
                    if (response.data != null) {
                        if (response.data.code == "1" || response.data.Code == "1") {
                            vm.ShowAlert(vm.$t("ApplySuccess", [vm.$t("View")]), 'success', true, vm.$t('Alert'));
                            vm.$emit('RefreshManageView');
                            vm.FetchData();
                        }
                        else {
                            vm.ShowAlert(vm.$t("AddedError", [vm.$t("View")]), 'failure', true, vm.$t('Alert'));
                        }
                    }
                    else {
                        vm.ShowAlert(vm.$t("AddedError", [vm.$t("View")]), 'failure', true, vm.$t('Alert'));
                    }
                });

            }
        },
        ForCheckBoxClear: function (ths) {
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });
            if (val.length > 0) {
                vm.listheaderbuttons[0].isdisabled = false;
                vm.listheaderbuttons[4].isdisabled = false;
                vm.listheaderbuttons[5].isdisabled = false;
