        FetchData: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `subModuleCode=Project_Detail&moduleName=PROJECT&pageSize=${vm.PageSize}&pageNumber=${vm.PageNumber}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&langCode=en&searchCondition=${vm.searchCondition}&fav=${vm.fav}`;
            await DataService.ProjectListing(url).then((response) => {
                if (response.data != null) {
                    vm.isLoading = false;
                    vm.Widget();
                    vm.Headers = response.data.result.schema;
                    vm.Headers.forEach((column) => {
                        column.DISPLAY_NAME = vm.$t(column.DISPLAY_NAME, column.COLUMN_NAME);
                        column.settings = null;
                        if (column.DATA_TYPE == 'date') {
                            column.DATA_TYPE = 'DATE';
                        }
                        if (column.DATA_TYPE == 'select' || column.DATA_TYPE == 'string') {
                            column.DATA_TYPE = 'text';
                        }
                        if (column.COLUMN_NAME == 'priority_id' || column.COLUMN_NAME == 'status_id' || column.COLUMN_NAME == 'planned_start_date' || column.COLUMN_NAME == 'planned_end_date' || column.COLUMN_NAME == 'current_progress' || column.COLUMN_NAME == 'estimated_hours' || column.COLUMN_NAME == 'currency_conversion_rate' || column.COLUMN_NAME == 'estimated_cost' || column.COLUMN_NAME == 'project_cost') {
                            column.settings = {
                                isInSlot: true
                            }
                        }
                        if (column.COLUMN_NAME == 'project_name') {
                            column.settings = {
                                isInSlot: true
                            }
                        }
                        if (column.COLUMN_NAME == 'industry_type_id' || column.COLUMN_NAME == 'template_id') {
                            column.DATA_TYPE = 'string';
                            column.settings = {
                                isInSlot: true
                            }
                        }
                    });
                    if (response.data.result.data != null) {
                        if (response.data.result.data.length > 0) {
                            vm.ProjectData = response.data.result.data;
                            vm.ProjectData.forEach((item) => {
                                if (item.is_sample_data == 1) {
                                    item.additionalClass = "sample-bar";
                                }
                                if (item.planned_start_date != '' || item.planned_start_date != null) {
                                    item.planned_start_date = new Date(item.planned_start_date);
                                }
                                if (item.planned_end_date != '' || item.planned_end_date != null) {
                                    item.planned_end_date = new Date(item.planned_end_date);
                                }

                            })
                            vm.TotalRecords = response.data.result.total_records[0];
                            vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                            vm.CurrentPage = vm.PageNumber;
                            vm.listheaderbuttons[0].isdisabled = true;
                            vm.listheaderbuttons[4].isdisabled = true;
                            vm.listheaderbuttons[5].isdisabled = true;
                            vm.listheaderbuttons[6].isdisabled = true;
                            vm.GetDdlRecords_ViewList();
                            vm.$nextTick(() => {
                                vm.resetAllCardStates();
                            });
                        } else {
                            vm.ProjectData = [];
                            vm.TotalRecords = 0;
                            vm.listheaderbuttons[0].isdisabled = true;
                            vm.listheaderbuttons[4].isdisabled = true;
                            vm.listheaderbuttons[5].isdisabled = true;
                            vm.listheaderbuttons[6].isdisabled = true;
                        }
                    }
                }
            })
        },
