                if (box.id !== 'action-list-box-' + projectId) {
                    box.style.display = 'none';
                    box.style.opacity = '0';
                    box.style.width = '0';
                    box.classList.remove('is-visible');
                }
            });
            const actionBox = document.getElementById('action-list-box-' + projectId);
            if (actionBox) {
                const isVisible = actionBox.style.display === 'block';
                if (isVisible) {
                    // Close if already open
                    actionBox.style.display = 'none';
                    actionBox.style.opacity = '0';
                    actionBox.style.width = '0';
                    actionBox.classList.remove('is-visible');
                } else {
                    // Open if closed
                    actionBox.style.display = 'block';
