    mounted() {
        this.handleClickOutside = (e) => {
            if (!e.target.closest('.verticle-action') &&
                !e.target.closest('.action-list-box') &&
                !e.target.closest('.action_icon') &&
                !e.target.closest('.actions-onclick')) {
                const allActionBoxes = document.querySelectorAll('.action-list-box');
                allActionBoxes.forEach(box => {
                    box.style.display = 'none';
                    box.style.opacity = '0';
                    box.style.width = '0';
                    box.classList.remove('is-visible');
                });
            }
        };
        document.addEventListener('click', this.handleClickOutside);
    },
    beforeDestroy() {
        if (this.handleClickOutside) {
            document.removeEventListener('click', this.handleClickOutside);
        }
    }

}
